using UnityEngine;\nusing UnityEngine.EventSystems;\n\npublic class SelectionManager : MonoBehaviour {\n    private Camera mainCamera;\n    private EventSystem eventSystem;\n\n    void Start() {\n        mainCamera = Camera.main;\n        eventSystem = EventSystem.current;\n    }\n\n    void Update() {\n        if (Input.GetMouseButtonDown(0)) { // Left mouse button\n            HandleLeftClick();\n        }\n    }\n\n    private void HandleLeftClick() {\n        if (eventSystem.IsPointerOverGameObject()) return; // Prevent selecting if UI is clicked\n\n        Ray ray = mainCamera.ScreenPointToRay(Input.mousePosition);\n        RaycastHit hit;\n\n        if (Physics.Raycast(ray, out hit)) {\n            // Check if the clicked object is a city or unit\n            if (hit.collider.CompareTag("City")) {\n                SelectCity(hit.collider.gameObject);\n            } else if (hit.collider.CompareTag("Unit")) {\n                SelectUnit(hit.collider.gameObject);\n            }\n        }\n    }\n\n    private void SelectCity(GameObject city) {\n        // Handle city selection and UI update\n        Debug.Log("City selected: " + city.name);\n        // TODO: Update UI to show city details\n    }\n\n    private void SelectUnit(GameObject unit) {\n        // Handle unit selection and UI update\n        Debug.Log("Unit selected: " + unit.name);\n        // TODO: Update UI to show unit details\n    }\n}